create or replace function GetUserChiefsHierarchy(&&StartUserId&& bigint) returns table ( &&StartItemId&& bigint, &&OrgItemId&& bigint, &&Lvl&& bigint, &&UserId&& bigint )
as $$
select us.&&OrgItemId&& as &&StartItemId&&, oih.* from &&UserSecuritySetCache&& us left join GetOrgItemHierarchy(us.&&OrgItemId&&) oih on 1=1 left join &&OrganizationItem&& oi on oi.&&Id&& = us.&&OrgItemId&& left join &&OrganizationItem&& oi1 on oi1.&&Id&& = oih.&&OrgItemId&& where us.&&UserId&& = $1 and us.&&UserCount&& != -1 and us.&&OrgItemId&& is not null and oi.&&ItemType&& in (1,2) and oi1.&&ItemType&& in (1) $$ language sql;

create or replace function FillUserSecuritySetCacheTest() returns void
as $$
$$ language sql;


create or replace function SplitString(
          &&Delimited&& text,
          &&Delimiter&& varchar(100))
returns table (&&Val&& text)

as
$$

declare 
p_Elems text[]; 

begin

	p_Elems := string_to_array($1, $2);
	return query select p_Elems[s] from generate_series(1,array_upper(p_Elems, 1)) as s;

end;

$$ 
language plpgsql;

create or replace function FillUserSecuritySetCache() returns void
as $$
-- маска которая оставляет только биты типа declare v_TypeMask bigint = 9151314442816847872; -- побитовый сдвиг влево 1111111 на 56 разрядов (2 ^ 56) 1111111[0]55 v_UserMask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55 v_GroupMask bigint = 144115188075855872; -- побитовый сдвиг влево 10 на 56 разрядов (2 ^ 56) 10[0]55 v_OrganizationItemMask bigint = 216172782113783808; -- побитовый сдвиг влево 11 на 56 разрядов (2 ^ 56) 11[0]55
begin
-- удаляем из кэша старые записи delete from &&UserSecuritySetCacheTemp&&;
-- начальники пользователей insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&UserCount&&) select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, min(&&Subordinate&&), -1 from ( select (u.&&Id&& | v_UserMask) as &&SetId&&, u.&&Id&& as &&UserId&&, u.&&Id&& as &&SubordinateUserId&&, 0 as &&Subordinate&& from &&User&& u union select (s.&&UserId&& | v_UserMask), u.&&Id&&, s.&&UserId&&, 1 from &&User&& u left join GetUserSubordinate(u.&&Id&&) s on 1 = 1 where s.&&UserId&& is not null ) s group by &&SetId&&, &&UserId&&, &&SubordinateUserId&&;
-- подразделения insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&OrgItemId&&, &&Subordinate&&, &&UserCount&&) with &&DepartmentUsers&& as ( select &&Id&&, &&UserId&&, &&UserCount&& from GetDepartmentsUsers() ) select (&&Id&& | v_OrganizationItemMask), &&UserId&&, &&Id&&, min(&&Subordinate&&), max(&&UserCount&&) from ( select &&Id&&, &&UserId&&, &&UserCount&&, 0 as &&Subordinate&& from &&DepartmentUsers&& union select gu.&&Id&&, ussc.&&UserId&&, -1, 1 from &&DepartmentUsers&& gu inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = gu.&&UserId&& ) s group by &&Id&&, &&UserId&&;
-- группы insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&GroupId&&, &&Subordinate&&, &&UserCount&&) with GroupUsers as ( select &&GroupId&& &&Id&&, &&UserId&&, &&UserCount&& from GetGroupsUsers() ) select (&&Id&& | v_GroupMask), &&UserId&&, max(&&GroupId&&), min(&&Subordinate&&), max(&&UserCount&&) from ( select &&Id&&, &&Id&& &&GroupId&&, &&UserId&&, &&UserCount&&, 0 as &&Subordinate&& from GroupUsers union select gu.&&Id&&, null, ussc.&&UserId&&, -1, 1 from GroupUsers gu inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = gu.&&UserId&& ) s group by &&Id&&, &&UserId&&;
-- переносим данные из кэша в боевую таблицу delete from &amp;&amp;UserSecuritySetCache&amp;&amp; where not exists(select &&SetId&& from &&UserSecuritySetCacheTemp&& t where t.&&SetId&&=&&UserSecuritySetCache&&.&&SetId&& and t.&&UserId&&=&&UserSecuritySetCache&&.&&UserId&& and t.&&Subordinate&&=&&UserSecuritySetCache&&.&&Subordinate&& and t.&&UserCount&&=&&UserSecuritySetCache&&.&&UserCount&&); insert into &&UserSecuritySetCache&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&GroupId&&, &&OrgItemId&&, &&UserCount&&) select t.&&SetId&&, t.&&UserId&&, t.&&SubordinateUserId&&, t.&&Subordinate&&, t.&&GroupId&&, t.&amp;&amp;OrgItemId&amp;&amp;, t.&&UserCount&& from &&UserSecuritySetCacheTemp&& t left join &&UserSecuritySetCache&& c on t.&&SetId&&=c.&&SetId&& and t.&&UserId&&=c.&&UserId&& and t.&&Subordinate&&=c.&&Subordinate&& and t.&&UserCount&&=c.&&UserCount&& where c.&&SetId&& is null;
end;
$$ language plpgsql;


create or replace function UpdateUserSecuritySetCache(
  &&UpdateData&& text,
  &&AuditUid&& uuid)
returns void

as
$$

  -- маска которая оставляет только биты типа
  declare
  v_TypeMask bigint = 9151314442816847872; -- 1111111[0]55
  v_UserMask bigint = 72057594037927936; -- побитовый сдвиг влево 1 на 56 разрядов (2 ^ 56) 1[0]55
  v_GroupMask bigint = 144115188075855872; -- побитовый сдвиг влево 10 на 56 разрядов (2 ^ 56) 10[0]55
  v_OrganizationItemMask bigint = 216172782113783808; -- побитовый сдвиг влево 11 на 56 разрядов (2 ^ 56) 11[0]55

  v_RefreshUsers int = 0;
  v_Separator int;
  v_ItemData text;
  v_AddUsersData text;
  v_RemoveUsersData text;
  v_AddOrgItemsData text;
  v_RemoveOrgItemsData text;
  v_AddGroupsData text;
  v_RemoveGroupsData text;
  v_ItemId bigint;
  v_SubItemId bigint;
  v_IsSubordinate int = 0;

begin

  delete from &&UUSSCGroupData&&;
  delete from &&UUSSCOrgItemData&&;

  -- парсим строку, записываем все во временную таблицу
  while (position(';' in $1) > 0) 
  loop
    v_Separator = position(';' in $1);
    v_ItemData = substring($1 from 1 for v_Separator - 1);
    UpdateData = substring($1 from v_Separator + 1);

    v_Separator = position(':' in v_ItemData);
    if (v_Separator > 0) then
	    begin
	      -- Данные для группы или элемента оргструктуры
	      v_ItemId = cast(substring(v_ItemData from 1 for v_Separator - 1) as bigint);
	      v_ItemData = substring(v_ItemData from v_Separator + 1);

	      v_Separator = position(':' in v_ItemData);
	      v_AddUsersData = substring(v_ItemData from 1 for v_Separator - 1);
	      v_ItemData = substring(v_ItemData from v_Separator + 1);

	      v_Separator = position(':' in v_ItemData);
	      if (v_Separator > 0) then
		      begin
			-- Данные для группы

			v_RemoveUsersData = substring(v_ItemData from 1 for v_Separator - 1);
			v_ItemData = substring(v_ItemData from v_Separator + 1);

			v_Separator = position(':' in v_ItemData);
			v_AddOrgItemsData = substring(v_ItemData from 1 for v_Separator - 1);
			v_ItemData = substring(v_ItemData from v_Separator + 1);

			v_Separator = position(':' in v_ItemData);
			v_RemoveOrgItemsData = substring(v_ItemData from 1 for v_Separator - 1);
			v_ItemData = substring(v_ItemData from v_Separator + 1);

			v_Separator = position(':' in v_ItemData);
			v_AddGroupsData = substring(v_ItemData from 1 for v_Separator - 1);
			v_RemoveGroupsData = substring(v_ItemData from v_Separator + 1);

			while (position(',' in v_AddUsersData) > 0)
			loop
			  v_Separator = position(',' in v_AddUsersData);
			  v_SubItemId = cast(substring(v_AddUsersData from 1 for v_Separator - 1) as bigint);
			  v_AddUsersData = substring(v_AddUsersData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, 1);
			end loop;

			while (position(',' in v_RemoveUsersData) > 0)
			loop
			  v_Separator = position(',' in v_RemoveUsersData);
			  v_SubItemId = cast(substring(v_RemoveUsersData from 1 for v_Separator - 1) as bigint);
			  v_RemoveUsersData = substring(v_RemoveUsersData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, -1);
			end loop;

			while (position(',' in v_AddOrgItemsData) > 0)
			loop
			  v_Separator = position(',' in v_AddOrgItemsData);
			  v_SubItemId = cast(substring(v_AddOrgItemsData from 1 for v_Separator - 1) as bigint);
			  v_AddOrgItemsData = substring(v_AddOrgItemsData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&OrgItemId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, 1);
			end loop;

			while (position(',' in v_RemoveOrgItemsData) > 0)
			loop
			  v_Separator = position(',' in v_RemoveOrgItemsData);
			  v_SubItemId = cast(substring(v_RemoveOrgItemsData from 1 for v_Separator - 1) as bigint);
			  v_RemoveOrgItemsData = substring(v_RemoveOrgItemsData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&OrgItemId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, -1);
			end loop;

			while (position(',' in v_AddGroupsData) > 0)
			loop
			  v_Separator = position(',' in v_AddGroupsData);
			  v_SubItemId = cast(substring(v_AddGroupsData from 1 for v_Separator - 1) as bigint);
			  v_AddGroupsData = substring(v_AddGroupsData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&GroupId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, 1);
			end loop;

			while (position(',' in v_RemoveGroupsData) > 0)
			loop
			  v_Separator = position(',' in v_RemoveGroupsData);
			  v_SubItemId = cast(substring(v_RemoveGroupsData from 1 for v_Separator - 1) as bigint);
			  v_RemoveGroupsData = substring(v_RemoveGroupsData from v_Separator + 1);
			  insert into &&UUSSCGroupData&&(&&Id&&, &&GroupId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, -1);
			end loop;
		      end;
	      else
		      begin
			-- Данные для элемента оргструктуры

			v_RemoveUsersData = substring(v_ItemData from v_Separator + 1);

			while (position(',' in v_AddUsersData) > 0)
			loop
			  v_Separator = position(',' in v_AddUsersData);
			  v_SubItemId = cast(substring(v_AddUsersData from 1 for v_Separator - 1) as bigint);
			  v_AddUsersData = substring(v_AddUsersData from v_Separator + 1);
			  insert into &&UUSSCOrgItemData&&(&&Id&&, &&UserId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, 1);
			end loop;

			while (position(',' in v_RemoveUsersData) > 0)
			loop
			  v_Separator = position(',' in v_RemoveUsersData);
			  v_SubItemId = cast(substring(v_RemoveUsersData from 1 for v_Separator - 1) as bigint);
			  v_RemoveUsersData = substring(v_RemoveUsersData from v_Separator + 1);
			  insert into &&UUSSCOrgItemData&&(&&Id&&, &&UserId&&, &&AddCount&&) values(v_ItemId, v_SubItemId, -1);
			end loop;
		      end;
	      end if;
	    end;
    else
	    begin
	      -- Нужно обновить данные по пользователям
	      v_RefreshUsers = 1;
	    end;
    end if;
  end loop;

  -- удаляем из кэша старые записи
  delete from &&UserSecuritySetCacheTemp&&;

  if (exists(select &&Id&& from &&UUSSCOrgItemData&&)) then
	  begin
	    -- рекурсивное добавление данных для содержащих отделов
	    insert into &&UUSSCOrgItemData&&(&&Id&&, &&UserId&&, &&AddCount&&)
	    select g.&&DepartmentId&&, d.&&UserId&&, d.&&AddCount&& from &&UUSSCOrgItemData&& d
	    inner join (select * from GetDepartments() where &&Id&&<>&&DepartmentId&&) g on g.&&Id&&=d.&&Id&&;


	    -- начальники пользователей
	    insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&UserCount&&)
	    select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, min(&&Subordinate&&), -1 from
	    (
	      select (u.&&Id&& | v_UserMask) as &&SetId&&, u.&&Id&& as &&UserId&&, u.&&Id&& as &&SubordinateUserId&&, 0 as &&Subordinate&& from &&User&& u
	      union
	      select (s.&&UserId&& | v_UserMask), u.&&Id&&, s.&&UserId&&, 1 from &&User&& u
	      left join GetUserSubordinate(u.&&Id&&) s on 1=1
	      where s.&&UserId&& is not null
	    ) s group by &&SetId&&, &&UserId&&, &&SubordinateUserId&&;


	    -- дублируем текущие записи об элементах орг структуры (без учета подчиненных пользователей)
	    insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&GroupId&&, &&OrgItemId&&, &&UserCount&&)
	    select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, t.&&GroupId&&, &&OrgItemId&&, &&UserCount&&
	    from &&UserSecuritySetCache&& t
	    where t.&&OrgItemId&& in (select &&Id&& from &&UUSSCOrgItemData&&) and t.&&Subordinate&&=0;

	    -- добавляем тех пользователей, которых нет в таблице
	    insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&OrgItemId&&, &&Subordinate&&, &&UserCount&&)
	    select (d.&&Id&& | v_OrganizationItemMask), d.&&UserId&&, d.&&Id&&, 0, 0
	    from &&UUSSCOrgItemData&& d
	    left join &&UserSecuritySetCacheTemp&& t on t.&&OrgItemId&&=d.&&Id&& and t.&&UserId&&=d.&&UserId&&
	    where d.&&UserId&& is not null and t.&&OrgItemId&& is null
	    group by d.&&Id&&, d.&&UserId&&;

	    -- изменяем количество ссылок на пользователей
	    update &&UserSecuritySetCacheTemp&& t
	    set &&UserCoun&&t=&&UserCount&&+(select sum(&&AddCount&&) from &&UUSSCOrgItemData&& where &&Id&&=t.&&OrgItemId&& and &&UserId&&=t.&&UserId&&)
	    where exists(select &&Id&& from &&UUSSCOrgItemData&& where &&Id&&=t.&&OrgItemId&& and &&UserId&&=t.&&UserId&&);


	    -- переводим изменения по элементам оргстуктуры в изменения по группам
	    insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&)
	    select m.&&GroupId&&, d.&&UserId&&, d.&&AddCount&& from &&UUSSCOrgItemData&& d
	    left join UserGroup_OrgItem_Map m on m.&&OrgItemId&&=d.&&Id&&
	    where m.&&GroupId&& is not null;
	  end;
  else 
	if (v_RefreshUsers = 1) then
		begin
			-- начальники пользователей
			insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&UserCount&&)
			select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, min(&&Subordinate&&), -1 from
			(
			select (u.&&Id&& | v_UserMask) as &&SetId&&, u.&&Id&& as &&UserId&&, u.&&Id&& as &&SubordinateUserId&&, 0 as &&Subordinate&& from &&User&& u
			union
			select (s.&&UserId&& | v_UserMask), u.&&Id&&, s.&&UserId&&, 1 from &&User&& u
			left join GetUserSubordinate(u.&&Id&&) s on 1=1
			where s.&&UserId&& is not null
			) s group by &&SetId&&, &&UserId&&, &&SubordinateUserId&&;
		end;
	end if;
 end if;

  -- переводим идентификаторы элементов оргструктуры в идентификаторы пользователей
  insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&)
  select d.&&Id&&, c.&&UserId&&, d.&&AddCount&& from &&UUSSCGroupData&& d
  inner join &&UserSecuritySetCache&& c on c.&&OrgItemId&& = d.&&OrgItemId&& and c.&&Subordinate&&=0;

  -- переводим идентификаторы групп в идентификаторы пользователей
  insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&)
  select d.&&Id&&, c.&&UserId&&, d.&&AddCount&& * c.&&UserCount&& from &&UUSSCGroupData&& d
  inner join &&UserSecuritySetCache&& c on c.&&GroupId&& = d.&&GroupId&& and c.&&Subordinate&&=0;

  -- рекурсивное добавление данных для родительских групп
  insert into &&UUSSCGroupData&&(&&Id&&, &&UserId&&, &&AddCount&&)
  select g.&&ChildGroupId&&, d.&&UserId&&, d.&&AddCount&& from &&UUSSCGroupData&& d
  inner join (select * from GetGroups() where &&ChildGroupId&&<>&&ParentGroupId&&) g on g.&&ParentGroupId&&=d.&&Id&&;


  -- дублируем текущие записи о группах (без учета подчиненных пользователей)
  insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&GroupId&&, &&OrgItemId&&, &&UserCount&&)
  select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, t.&&GroupId&&, &&OrgItemId&&, &&UserCount&&
  from &&UserSecuritySetCache&& t
  where t.&&GroupId&& in (select &&Id&& from &&UUSSCGroupData&&) and t.&&Subordinate&&=0;

  -- добавляем тех пользователей, которых нет в таблице
  insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&GroupId&&, &&Subordinate&&, &&UserCount&&)
  select (d.&&Id&& | v_GroupMask), d.&&UserId&&, d.&&Id&&, 0, 0
  from &&UUSSCGroupData&& d
  left join &&UserSecuritySetCacheTemp&& t on t.&&GroupId&&=d.&&Id&& and t.&&UserId&&=d.&&UserId&&
  where d.&&UserId&& is not null and t.&&GroupId&& is null
  group by d.&&Id&&, d.&&UserId&&;

  -- изменяем количество ссылок на пользователей
  update &&UserSecuritySetCacheTemp&& t
  set &&UserCount&&=&&UserCount&&+(select sum(&&AddCount&&) from &&UUSSCGroupData&& where &&Id&&=t.&&GroupId&& and &&UserId&&=t.&&UserId&&)
  where exists(select &&Id&& from &&UUSSCGroupData&& where &&Id&&=t.&&GroupId&& and &&UserId&&=t.&&UserId&&);

  -- удаляем записи без ссылок
  delete from &&UserSecuritySetCacheTemp&& where &&UserCount&&<=0 and &&SubordinateUserId&& is null;


  -- переносим данные из кэша в боевую таблицу
  if (exists(select &&Id&& from &&UUSSCOrgItemData&&)) then
	  begin
	    insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&GroupId&&, &&OrgItemId&&, &&Subordinate&&, &&UserCount&&)
	    -- добавляем записи подчиненных пользователей для измененных данных (подчинения берем из временной таблицы, в ней актуальные данные)
	    select t.&&SetId&&, ussc.&&UserId&&, cast(null as bigint), t.&&OrgItemId&&, 1, -1 from &&UserSecuritySetCacheTemp&& t
	    inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = t.&&UserId&&
	    left join &&UserSecuritySetCacheTemp&& st on st.&&SetId&& = t.&&SetId&& and st.&&UserId&& = ussc.&&UserId&&
	    where st.&&SetId&& is null and t.&&SubordinateUserId&& is null
	    union
	    -- добавляем записи подчиненных пользователей для данных, которые не меняются (подчинения берем из временной таблицы, в ней актуальные данные)
	    select t.&&SetId&&, ussc.&&UserId&&, null, t.&&OrgItemId&&, 1, -1 from &&UserSecuritySetCache&& t
	    inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = t.&&UserId&&
	    left join &&UserSecuritySetCache&& st on st.&&SetId&& = t.&&SetId&& and st.&&UserId&& = ussc.&&UserId&& and st.&&Subordinate&&=0
	    left join &&UUSSCOrgItemData&& oid on t.&&OrgItemId&&=oid.&&Id&&
	    left join &&UUSSCGroupData&& gd on t.&&GroupId&&=gd.&&Id&&
	    where t.&&Subordinate&&=0 and st.&&SetId&& is null and oid.&&Id&& is null and gd.&&Id&& is null and t.&&SubordinateUserId&& is null;

	    v_IsSubordinate = 2;    
	  end;
  else 
	if (v_RefreshUsers = 1) then
		begin
			insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&GroupId&&, &&OrgItemId&&, &&Subordinate&&, &&UserCount&&)
			-- добавляем записи подчиненных пользователей для измененных данных (подчинения берем из временной таблицы, в ней актуальные данные)
			select t.&&SetId&&, ussc.&&UserId&&, cast(null as bigint), t.&&OrgItemId&&, 1, -1 from &&UserSecuritySetCacheTemp&& t
			inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = t.&&UserId&&
			left join &&UserSecuritySetCacheTemp&& st on st.&&SetId&& = t.&&SetId&& and st.&&UserId&& = ussc.&&UserId&&
			where st.&&SetId&& is null and t.&&SubordinateUserId&& is null
			union
			-- добавляем записи подчиненных пользователей для данных, которые не меняются (подчинения берем из временной таблицы, в ней актуальные данные)
			select t.&&SetId&&, ussc.&&UserId&&, null, t.&&OrgItemId&&, 1, -1 from &&UserSecuritySetCache&& t
			inner join &&UserSecuritySetCacheTemp&& ussc on ussc.&&SubordinateUserId&& = t.&&UserId&&
			left join &&UserSecuritySetCache&& st on st.&&SetId&& = t.&&SetId&& and st.&&UserId&& = ussc.&&UserId&& and st.&&Subordinate&&=0
			left join &&UUSSCOrgItemData&& oid on t.&&OrgItemId&&=oid.&&Id&&
			left join &&UUSSCGroupData&& gd on t.&&GroupId&&=gd.&&Id&&
			where t.&&Subordinate&&=0 and st.&&SetId&& is null and oid.&&Id&& is null and gd.&&Id&& is null and t.&&SubordinateUserId&& is null;

			v_IsSubordinate = 1;    
		end;
	  else
		  begin
		    -- добавляем записи подчиненных пользователей (подчинения берем из основной таблице, они не меняются в текущей итерации)
		    insert into &&UserSecuritySetCacheTemp&& (&&SetId&&, &&UserId&&, &&GroupId&&, &&OrgItemId&&, &&Subordinate&&, &&UserCount&&)
		    select distinct t.&&SetId&&, ussc.&&UserId&&, cast(null as bigint), t.&&OrgItemId&&, 1, -1 from &&UserSecuritySetCacheTemp&& t
		    inner join &&UserSecuritySetCache&& ussc on ussc.&&SubordinateUserId&& = t.&&UserId&&
		    left join &&UserSecuritySetCacheTemp&& st on st.&&SetId&& = t.&&SetId&& and st.&&UserId&& = ussc.&&UserId&&
		    where st.&&SetId&& is null;
		  end;
	  end if;
  end if;

  insert into &&HistoryUserSecuritySetCache&&(&&Id&&, &&UserId&&, &&OrgItemId&&, &&GroupId&&, &&SetId&&, &&Uid&&, &&AddCount&&)
  select g.&&Id&&, g.&&UserId&&, g.&&OrgItemId&&, g.&&GroupId&&, g.&&SetId&&, $2, g.&&AddCount&&
  from &&UUSSCGroupData&& g
  left join &&UserSecuritySetCacheTemp&& c     
  on c.&&SetId&& = g.&&SetId&& and c.&&UserId&& = g.&&UserId&&
  where (g.&&UserId&& is not null or g.&&OrgItemId&& is not null or g.&&GroupId&& is not null) 
            and (coalesce(c.&&UserCount&&, g.&&AddCount&&) - g.&&AddCount&& = 0 or G.&&UserId&& is null);

  if (v_IsSubordinate > 0) then
	  begin
	    -- удаляем из основной таблицы все данные по подчинениям по элементам оргструктуры и группам
	    delete from &&UserSecuritySetCache&& where &&Subordinate&&=1;

	    -- удаляем начальников пользователей (эти данные есть во временной таблице)
	    delete from &&UserSecuritySetCache&& where (&&SetId&& & v_TypeMask)=v_UserMask;

	    if (v_IsSubordinate > 1) then
