			update &&UUSSCOrgItemData&& set &&SetId&&=(&&Id&& | v_OrganizationItemMask);
			delete from &&UserSecuritySetCache&& where &&SetId&& in (select &&SetId&& from &&UUSSCOrgItemData&& t);
		    end;
	    end if;
	  end;
  end if;

  -- удаляем данные по измененным группам
  update &&UUSSCGroupData&& set &&SetId&&=(&&Id&& | v_GroupMask);

  delete from &&UserSecuritySetCache&& where &&SetId&& in (select &&SetId&& from &&UUSSCGroupData&& t);
  -- добавляем все, что есть во временной таблице (предварительно все лишние данные были удалены)
  insert into &&UserSecuritySetCache&& (&&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&GroupId&&, &&OrgItemId&&, &&UserCount&&) select &&SetId&&, &&UserId&&, &&SubordinateUserId&&, &&Subordinate&&, &&GroupId&&, &&OrgItemId&&, &&UserCount&& from &&UserSecuritySetCacheTemp&& t;

  insert into &&HistoryUserSecuritySetCache&&(&&Uid&&)
  values($2);

end;

